sys_script_include.script:
var dm_import = Class.create();

dm_import.prototype = {

    initialize: function() {
        this.recordsImported = 0;

        // Scoped apps are blocked from writing to these system-managed fields
        this.blockedFields = ['sys_mod_count', 'sys_created_on', 'sys_updated_on', 'sys_created_by', 'sys_updated_by', 'sys_tags'];

        // ADDED 'sla_timer_config_mapping' to the blocked tables array
        this.blockedTables = ['sys_audit', 'sys_audit_relation', 'sla_timer_config_mapping'];
    },


    processXML: function(xmlString) {

        if (!xmlString || xmlString.indexOf('<unload') === -1) {

            return { error: "Invalid XML format. Must be a standard ServiceNow <unload> payload.", count: 0 };

        }



        try {

            var xmlDoc = new XMLDocument2();

            xmlDoc.parseXML(xmlString);



            var root = xmlDoc.getDocumentElement();

            if (!root || root.getNodeName() !== 'unload') {

                return { error: "Failed to find <unload> root node.", count: 0 };

            }



            var recordNodeIter = root.getChildNodeIterator();



            while (recordNodeIter.hasNext()) {

                var recordNode = recordNodeIter.next();

                var tableName = recordNode.getNodeName();



                if (tableName === '#text') continue;



                this._processRecordNode(tableName, recordNode);

            }



            return { error: "", count: this.recordsImported };



        } catch (ex) {

            return { error: String(ex.message), count: this.recordsImported };

        }

    },



   _processRecordNode: function(tableName, recordNode) {

        // Stop immediately if it's a blocked system table

        if (this.blockedTables.indexOf(tableName) !== -1) return;



        var fieldIter = recordNode.getChildNodeIterator();

        var fields = {};

        var payload = '';



        while (fieldIter.hasNext()) {

            var fieldNode = fieldIter.next();

            var fName = fieldNode.getNodeName();



            if (fName === '#text') continue;



            var fVal = fieldNode.getTextContent() || '';



            if (tableName === 'sys_attachment' && fName === 'payload') {

                payload = fVal;

            } else {

                fields[fName] = fVal;

            }

        }



        var sysId = fields['sys_id'];

        if (!sysId) return;



        if (tableName === 'sys_attachment' && payload) {

            this._processAttachment(fields, payload);

            return;

        }



        try {

            // Hand the data over the wall to our Global Bridge!

            var bridge = new global.TraceNowGlobalBridge();



            // Pass the fields as a JSON string to easily cross the scope boundary

            var isSuccess = bridge.insertOrUpdate(tableName, sysId, JSON.stringify(fields));



            if (isSuccess) {

                this.recordsImported++;

            } else {

                gs.warn("TraceNow: Global Bridge blocked by dictionary ACLs for " + tableName);

            }

        } catch (tableEx) {

            gs.warn("TraceNow: Failed to reach Global Bridge: " + tableEx.message);

        }

    },



    _processAttachment: function(fields, base64Payload) {

        try {

            var existingAtt = new GlideRecord('sys_attachment');

            if (existingAtt.get(fields['sys_id'])) return;



            var targetGr = new GlideRecord(fields['table_name']);

            if (targetGr.get(fields['table_sys_id'])) {

                var gsa = new GlideSysAttachment();

                gsa.writeBase64(

                    targetGr,

                    fields['file_name'] || 'imported_file',

                    fields['content_type'] || 'application/octet-stream',

                    base64Payload

                );

                this.recordsImported++;

            }

        } catch (attEx) {}

    },



    type: 'dm_import'

};
